import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import rehypeHighlight from "rehype-highlight";

interface Props {
  content: string;
}

/**
 * Renders agent response text as formatted markdown.
 *
 * Features:
 * - GitHub-Flavored Markdown (tables, strikethrough, task lists, autolinks)
 * - Syntax-highlighted fenced code blocks (via highlight.js github-dark theme)
 * - Inline code pill styling
 * - Dark-UI-matched prose via .agent-prose (globals.css)
 */
export function MarkdownContent({ content }: Props) {
  return (
    <div className="agent-prose">
      <ReactMarkdown
        remarkPlugins={[remarkGfm]}
        rehypePlugins={[rehypeHighlight]}
        components={{
          // Open links in new tab (agent responses may include URLs)
          a: ({ href, children, ...props }) => (
            <a
              href={href}
              target="_blank"
              rel="noopener noreferrer"
              {...props}
            >
              {children}
            </a>
          ),
        }}
      >
        {content}
      </ReactMarkdown>
    </div>
  );
}

import { useRef, useState, useEffect } from "react";
import { MarkdownContent } from "./MarkdownContent";

interface Props {
  text: string;
  streaming?: boolean;
}

export function StreamingText({ text, streaming = false }: Props) {
  const [displayed, setDisplayed] = useState(text);
  const rafRef = useRef<number | undefined>(undefined);
  const pendingRef = useRef(text);

  useEffect(() => {
    pendingRef.current = text;
    if (!rafRef.current) {
      rafRef.current = requestAnimationFrame(() => {
        setDisplayed(pendingRef.current);
        rafRef.current = undefined;
      });
    }
    return () => {
      if (rafRef.current) {
        cancelAnimationFrame(rafRef.current);
        rafRef.current = undefined;
      }
    };
  }, [text]);

  return (
    <div className="relative">
      <MarkdownContent content={displayed} />
      {streaming && (
        <span className="cursor-blink ml-0.5 inline-block w-1.5 h-4 bg-green-400 align-middle" />
      )}
    </div>
  );
}

